import React, { useEffect, useState, useCallback } from 'react';
import { useAuth } from '../context/AuthContext';
import { ENDPOINTS } from '../api';

type DeliveryAddress = string | { address: string; latitude?: number; longitude?: number };

function getAddressStr(addr?: DeliveryAddress): string {
  if (!addr) return '';
  if (typeof addr === 'object') return addr.address || '';
  return addr;
}

interface Order {
  order_id: string;
  status: string;
  driver_id?: string | null;
  delivery_address?: DeliveryAddress;
  district?: string;
  priority?: string;
  total_price?: number;
  totalAmount?: number;
  customer_id?: string;
  customer_name?: string;
  items?: Array<{ name: string; quantity: number; price: number }>;
  created_at?: string;
}

// Status sort order — ready-to-deliver first so available orders surface to top
const STATUS_SORT: Record<string, number> = {
  'ready-to-deliver': 0, accepted: 1, 'on-delivery': 2, delivered: 3, cancelled: 4,
};

const STATUS_CONFIG: Record<string, { label: string; bg: string; text: string; accent: string }> = {
  'ready-to-deliver': { label: 'Ready to Deliver', bg: '#f3e8ff', text: '#6b21a8', accent: '#7c3aed' },
  accepted:           { label: 'Accepted',         bg: '#ccfbf1', text: '#115e59', accent: '#0d9488' },
  'on-delivery':      { label: 'On Delivery',      bg: '#ffedd5', text: '#9a3412', accent: '#ea580c' },
  delivered:          { label: 'Delivered',         bg: '#dcfce7', text: '#166534', accent: '#16a34a' },
  cancelled:          { label: 'Cancelled',         bg: '#fee2e2', text: '#991b1b', accent: '#dc2626' },
};

const PRIORITY_COLORS: Record<string, { bg: string; text: string }> = {
  high:   { bg: '#fee2e2', text: '#dc2626' },
  medium: { bg: '#fefce8', text: '#ca8a04' },
  low:    { bg: '#f0fdf4', text: '#16a34a' },
};

// ─── 4-step timeline ─────────────────────────────────────────────────────────
const TIMELINE = [
  { key: 'ready-to-deliver', label: 'Ready',    icon: 'inventory_2' },
  { key: 'accepted',         label: 'Accepted', icon: 'check_circle' },
  { key: 'on-delivery',      label: 'On Route', icon: 'local_shipping' },
  { key: 'delivered',        label: 'Delivered',icon: 'where_to_vote' },
];
const TIMELINE_IDX: Record<string, number> = {
  'ready-to-deliver': 0, accepted: 1, 'on-delivery': 2, delivered: 3,
};

function OrderTimeline({ status }: { status: string }) {
  const cur = TIMELINE_IDX[status] ?? -1;
  return (
    <div style={{ display: 'flex', alignItems: 'center', padding: '10px 0 6px' }}>
      {TIMELINE.map((step, i) => {
        const done   = i <= cur;
        const active = i === cur;
        return (
          <React.Fragment key={step.key}>
            <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', flex: 1 }}>
              <div style={{
                width: 30, height: 30, borderRadius: '50%',
                background: done ? '#0d9488' : '#f1f5f9',
                border: `2px solid ${done ? '#0d9488' : '#e2e8f0'}`,
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                boxShadow: active ? '0 0 0 4px #ccfbf155' : 'none',
              }}>
                <span className="material-icons-round" style={{ fontSize: 14, color: done ? '#fff' : '#94a3b8' }}>{step.icon}</span>
              </div>
              <div style={{ fontSize: 9, fontWeight: active ? 700 : 500, color: active ? '#0d9488' : done ? '#475569' : '#94a3b8', marginTop: 3, textAlign: 'center' }}>
                {step.label}
              </div>
            </div>
            {i < TIMELINE.length - 1 && (
              <div style={{ flex: 1, height: 2, marginBottom: 16, background: i < cur ? '#0d9488' : '#e2e8f0' }} />
            )}
          </React.Fragment>
        );
      })}
    </div>
  );
}

export default function Orders() {
  const { user, token } = useAuth();
  const [orders, setOrders] = useState<Order[]>([]);
  const [loading, setLoading] = useState(true);
  const [updating, setUpdating] = useState<string | null>(null);
  const [expandedId, setExpandedId] = useState<string | null>(null);
  const [msg, setMsg] = useState<{ type: 'ok' | 'err'; text: string } | null>(null);

  const fetchOrders = useCallback(async () => {
    try {
      const res = await fetch(ENDPOINTS.orders, { headers: { Authorization: `Bearer ${token}` } });
      const data = await res.json();
      const arr: Order[] = Array.isArray(data) ? data : data.orders || [];
      arr.sort((a, b) => (STATUS_SORT[a.status] ?? 9) - (STATUS_SORT[b.status] ?? 9));
      setOrders(arr);
    } catch { /* ignore */ } finally { setLoading(false); }
  }, [token]);

  useEffect(() => { fetchOrders(); }, [fetchOrders]);

  const handleAction = async (order: Order, action: string) => {
    setUpdating(order.order_id);
    setMsg(null);
    try {
      let endpoint = '';
      const body: Record<string, string> = { order_id: order.order_id, driver_id: user?.driver_id || '' };

      if (action === 'accept')           endpoint = ENDPOINTS.acceptOrder;
      else if (action === 'on_delivery') endpoint = ENDPOINTS.onDelivery;
      else if (action === 'deliver')     endpoint = ENDPOINTS.deliver;
      else throw new Error('Unknown action');

      const res = await fetch(endpoint, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${token}` },
        body: JSON.stringify(body),
      });
      const data = await res.json();
      // FastAPI errors come as { detail: "..." }, Express as { message/error: "..." }
      if (!res.ok) throw new Error(data.detail || data.error || data.message || `HTTP ${res.status}`);
      setMsg({ type: 'ok', text: 'Status updated successfully!' });
      await fetchOrders();
    } catch (err: any) {
      setMsg({ type: 'err', text: err.message });
    } finally { setUpdating(null); }
  };

  const available = orders.filter(o => o.status === 'ready-to-deliver').length;
  const inProgress = orders.filter(o => ['accepted','on-delivery'].includes(o.status) && o.driver_id === user?.driver_id).length;

  return (
    <div>
      {/* Header */}
      <div style={{ background: '#fff', padding: '16px 20px', borderBottom: '1px solid #f1f5f9' }}>
        <div style={{ fontSize: 20, fontWeight: 800, color: '#0f172a' }}>All Orders</div>
        <div style={{ fontSize: 12, color: '#94a3b8', marginTop: 2 }}>
          {orders.length} total · {available} available · {inProgress} in progress
        </div>
      </div>

      <div style={{ padding: 16 }}>
        {msg && (
          <div style={{
            background: msg.type === 'ok' ? '#f0fdf4' : '#fef2f2',
            border: `1px solid ${msg.type === 'ok' ? '#bbf7d0' : '#fecaca'}`,
            color: msg.type === 'ok' ? '#166534' : '#dc2626',
            borderRadius: 12, padding: '10px 14px', fontSize: 13, marginBottom: 12,
          }}>{msg.text}</div>
        )}

        {loading ? (
          <div style={{ textAlign: 'center', padding: 48, color: '#64748b' }}>Loading…</div>
        ) : orders.length === 0 ? (
          <div style={{ textAlign: 'center', padding: 60 }}>
            <span className="material-icons-round" style={{ fontSize: 44, color: '#94a3b8', marginBottom: 12, display: 'block' }}>inbox</span>
            <div style={{ fontSize: 16, fontWeight: 700, color: '#475569' }}>No orders yet</div>
          </div>
        ) : (
          orders.map(order => {
            const sc = STATUS_CONFIG[order.status] ?? { label: order.status, bg: '#f1f5f9', text: '#64748b', accent: '#94a3b8' };
            const pc = order.priority ? PRIORITY_COLORS[order.priority] : null;
            const isExpanded = expandedId === order.order_id;
            const price = order.total_price ?? order.totalAmount;
            const isMyOrder = order.driver_id === user?.driver_id;

            return (
              <div key={order.order_id} style={{
                background: '#fff', borderRadius: 18, marginBottom: 10,
                border: `1px solid ${isMyOrder && order.status !== 'delivered' ? '#ccfbf1' : '#f1f5f9'}`,
                overflow: 'hidden',
              }}>
                {/* Accent stripe */}
                <div style={{ height: 3, background: sc.accent }} />

                {/* Header row */}
                <div onClick={() => setExpandedId(isExpanded ? null : order.order_id)}
                  style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', padding: 16, cursor: 'pointer' }}
                >
                  <div style={{ flex: 1, marginRight: 8 }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: 6, flexWrap: 'wrap' }}>
                      <div style={{ fontSize: 14, fontWeight: 700, color: '#0f172a' }}>Order #{order.order_id?.slice(-8)}</div>
                      {isMyOrder && order.status !== 'delivered' && (
                        <span style={{ fontSize: 10, fontWeight: 700, background: '#ccfbf1', color: '#0d9488', padding: '2px 7px', borderRadius: 20 }}>MINE</span>
                      )}
                    </div>
                    <div style={{ fontSize: 12, color: '#64748b', marginTop: 2, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                      {getAddressStr(order.delivery_address) || order.district || '—'}
                    </div>
                    {price != null && (
                      <div style={{ fontSize: 12, fontWeight: 600, color: '#0d9488', marginTop: 2 }}>Rs. {Number(price).toFixed(2)}</div>
                    )}
                  </div>
                  <div style={{ textAlign: 'right', flexShrink: 0 }}>
                    <span style={{
                      display: 'inline-block', background: sc.bg, color: sc.text,
                      fontSize: 11, fontWeight: 700, padding: '4px 10px', borderRadius: 20,
                    }}>{sc.label}</span>
                    {pc && (
                      <span style={{
                        display: 'block', background: pc.bg, color: pc.text,
                        fontSize: 11, fontWeight: 700, padding: '3px 8px', borderRadius: 20, marginTop: 4,
                        textTransform: 'capitalize',
                      }}>{order.priority}</span>
                    )}
                    <span className="material-icons-round" style={{ fontSize: 16, color: '#94a3b8', marginTop: 4, display: 'block' }}>
                      {isExpanded ? 'expand_less' : 'expand_more'}
                    </span>
                  </div>
                </div>

                {/* Timeline — always visible */}
                <div style={{ padding: '0 16px', borderTop: '1px solid #f8fafc' }}>
                  <OrderTimeline status={order.status} />
                </div>

                {/* Expanded detail + action buttons */}
                {isExpanded && (
                  <div style={{ padding: '12px 16px 16px', borderTop: '1px solid #f8fafc' }}>
                    {order.customer_name && <InfoRow label="Customer" value={order.customer_name} />}
                    {order.customer_id   && <InfoRow label="Customer ID" value={order.customer_id} />}
                    {order.district      && <InfoRow label="District" value={order.district} />}
                    {order.created_at    && <InfoRow label="Created" value={new Date(order.created_at).toLocaleString()} />}

                    {/* Accept — available to ANY driver when order is ready-to-deliver */}
                    {order.status === 'ready-to-deliver' && (
                      <ActionBtn label="Accept Order" icon="check_circle" color="#7c3aed"
                        loading={updating === order.order_id}
                        onClick={() => handleAction(order, 'accept')} />
                    )}
                    {/* Start Delivery — only for this driver's accepted order */}
                    {order.status === 'accepted' && isMyOrder && (
                      <ActionBtn label="Start Delivery" icon="local_shipping" color="#ea580c"
                        loading={updating === order.order_id}
                        onClick={() => handleAction(order, 'on_delivery')} />
                    )}
                    {/* Mark Delivered — only for this driver's on-delivery order */}
                    {order.status === 'on-delivery' && isMyOrder && (
                      <ActionBtn label="Mark Delivered" icon="where_to_vote" color="#16a34a"
                        loading={updating === order.order_id}
                        onClick={() => handleAction(order, 'deliver')} />
                    )}
                  </div>
                )}
              </div>
            );
          })
        )}
      </div>
    </div>
  );
}

function InfoRow({ label, value }: { label: string; value: string }) {
  return (
    <div style={{ display: 'flex', marginBottom: 6 }}>
      <span style={{ fontSize: 12, color: '#94a3b8', width: 96, flexShrink: 0 }}>{label}</span>
      <span style={{ fontSize: 12, color: '#475569', fontWeight: 500 }}>{value}</span>
    </div>
  );
}

function ActionBtn({ label, icon, color, loading, onClick }: {
  label: string; icon: string; color: string; loading: boolean; onClick: () => void;
}) {
  return (
    <button disabled={loading} onClick={onClick} style={{
      width: '100%', background: color, color: '#fff', border: 'none',
      borderRadius: 12, padding: '12px 0', fontSize: 14, fontWeight: 700,
      marginTop: 12, cursor: loading ? 'not-allowed' : 'pointer',
      opacity: loading ? 0.6 : 1, boxShadow: `0 3px 8px ${color}44`,
      display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 8,
    }}>
      {loading
        ? 'Updating…'
        : <><span className="material-icons-round" style={{ fontSize: 18 }}>{icon}</span>{label}</>
      }
    </button>
  );
}
